{
  "sentences": [
    {
      "text": "我常常在週末打籃球。",
      "pinyin": "Wǒ chángcháng zài zhōumò dǎ lánqiú.",
      "pinyin_numeric": "wo3 chang2chang2 zai4 zhou1mo4 da3 lan2qiu2",
      "translation_en": "I often play basketball on weekends.",
      "translation_ko": "저는 주말에 자주 농구를 합니다."
    },
    {
      "text": "他常常跟朋友一起踢足球。",
      "pinyin": "Tā chángcháng gēn péngyǒu yīqǐ tī zúqiú.",
      "pinyin_numeric": "ta1 chang2chang2 gen1 peng2you3 yi1qi3 ti1 zu2qiu2",
      "translation_en": "He often plays soccer with friends.",
      "translation_ko": "그는 친구들과 함께 자주 축구를 합니다."
    },
    {
      "text": "她常常在家裡看小說。",
      "pinyin": "Tā chángcháng zài jiā lǐ kàn xiǎoshuō.",
      "pinyin_numeric": "ta1 chang2chang2 zai4 jia1 li3 kan4 xiao3shuo1",
      "translation_en": "She often reads novels at home.",
      "translation_ko": "그녀는 집에서 자주 소설을 봅니다."
    },
    {
      "text": "我們常常一起去爬山。",
      "pinyin": "Wǒmen chángcháng yīqǐ qù páshān.",
      "pinyin_numeric": "wo3men chang2chang2 yi1qi3 qu4 pa2shan1",
      "translation_en": "We often go hiking together.",
      "translation_ko": "우리는 함께 자주 등산을 갑니다."
    },
    {
      "text": "你常常聽廣播嗎？",
      "pinyin": "Nǐ chángcháng tīng guǎngbò ma?",
      "pinyin_numeric": "ni3 chang2chang2 ting1 guang3bo4 ma0",
      "translation_en": "Do you often listen to the radio?",
      "translation_ko": "당신은 자주 라디오를 듣나요?"
    },
    {
      "text": "我妹妹常常在家裡畫畫。",
      "pinyin": "Wǒ mèimei chángcháng zài jiā lǐ huàhuà.",
      "pinyin_numeric": "wo3 mei4mei chang2chang2 zai4 jia1 li3 hua4hua4",
      "translation_en": "My younger sister often draws at home.",
      "translation_ko": "제 여동생은 집에서 자주 그림을 그립니다."
    },
    {
      "text": "他常常在公園騎腳踏車。",
      "pinyin": "Tā chángcháng zài gōngyuán qí jiǎotàchē.",
      "pinyin_numeric": "ta1 chang2chang2 zai4 gong1yuan2 qi2 jiao3ta4che1",
      "translation_en": "He often rides a bike in the park.",
      "translation_ko": "그는 공원에서 자주 자전거를 탑니다."
    },
    {
      "text": "我爸爸常常看球賽。",
      "pinyin": "Wǒ bàba chángcháng kàn qiúsài.",
      "pinyin_numeric": "wo3 ba4ba chang2chang2 kan4 qiu2sai4",
      "translation_en": "My father often watches ball games.",
      "translation_ko": "제 아버지는 자주 경기를 보십니다."
    },
    {
      "text": "你哥哥常常打電動嗎？",
      "pinyin": "Nǐ gēge chángcháng dǎ diàndòng ma?",
      "pinyin_numeric": "ni3 ge1ge chang2chang2 da3 dian4dong4 ma0",
      "translation_en": "Does your older brother often play video games?",
      "translation_ko": "당신의 오빠는 자주 게임을 하나요?"
    },
    {
      "text": "我常常跟朋友一起看演唱會。",
      "pinyin": "Wǒ chángcháng gēn péngyǒu yīqǐ kàn yǎnchànghuì.",
      "pinyin_numeric": "wo3 chang2chang2 gen1 peng2you3 yi1qi3 kan4 yan3chang4hui4",
      "translation_en": "I often go to concerts with friends.",
      "translation_ko": "저는 친구들과 함께 자주 콘서트를 봅니다."
    }
  ]
}
